  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→import { logError, logInfo, logWarn } from "../http/observability";
 13→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 14→import type { IntentStatus } from "../intent/types";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types — exported for tests
 18→// ---------------------------------------------------------------------------
 19→
 20→export type SessionDeps = {
 21→  surreal: Surreal;
 22→  shellExec: ShellExec;
 23→  brainBaseUrl: string;
 24→  spawnAgent?: SpawnAgentFn;
 25→};
 26→
 27→export type SessionErrorCode =
 28→  | "TASK_NOT_FOUND"
 29→  | "TASK_NOT_ASSIGNABLE"
 30→  | "AGENT_ALREADY_ACTIVE"
 31→  | "WORKSPACE_MISMATCH"
 32→  | "MISSING_TASK_ID"
 33→  | "WORKTREE_ERROR"
 34→  | "SESSION_NOT_FOUND"
 35→  | "SESSION_ERROR"
 36→  | "INTENT_NOT_AUTHORIZED";
 37→
 38→export type SessionError = {
 39→  code: SessionErrorCode;
 40→  message: string;
 41→  httpStatus: number;
 42→};
 43→
 44→export type SessionResult<T> =
 45→  | { ok: true; value: T }
 46→  | { ok: false; error: SessionError };
 47→
 48→export type OrchestratorSessionResult = SessionResult<{
 49→  agentSessionId: string;
 50→  streamId: string;
 51→  worktreeBranch: string;
 52→}>;
 53→
 54→export type SessionStatusResult = SessionResult<{
 55→  orchestratorStatus: OrchestratorStatus;
 56→  worktreeBranch?: string;
 57→  worktreePath?: string;
 58→  lastEventAt?: string;
 59→  startedAt?: string;
 60→  error?: string;
 61→}>;
 62→
 63→export type AbortSessionResult = SessionResult<{
 64→  aborted: boolean;
 65→  sessionId: string;
 66→}>;
 67→
 68→export type AcceptSessionResult = SessionResult<{
 69→  accepted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type ReviewResult = SessionResult<{
 74→  taskTitle: string;
 75→  diff: import("./worktree-manager").DiffResult;
 76→  session: {
 77→    orchestratorStatus: string;
 78→    worktreeBranch?: string;
 79→    startedAt?: string;
 80→    lastEventAt?: string;
 81→    toolCallCount?: number;
 82→    filesEdited?: number;
 83→  };
 84→}>;
 85→
 86→export type RejectSessionResult = SessionResult<{
 87→  rejected: boolean;
 88→  continuing: boolean;
 89→}>;
 90→
 91→export type PromptSessionResult = SessionResult<{
 92→  delivered: boolean;
 93→}>;
 94→
 95→// ---------------------------------------------------------------------------
 96→// In-memory handle registry — maps agentSessionId to AgentHandle
 97→// ---------------------------------------------------------------------------
 98→
 99→const handleRegistry = new Map<string, AgentHandle>();
100→
101→// Exported for testing cleanup
102→export function clearHandleRegistry(): void {
103→  handleRegistry.clear();
104→}
105→
106→export function getHandle(sessionId: string): AgentHandle | undefined {
107→  return handleRegistry.get(sessionId);
108→}
109→
110→// ---------------------------------------------------------------------------
111→// Event iteration — port (dependencies as function signatures)
112→// ---------------------------------------------------------------------------
113→
114→export type EventIterationDeps = {
115→  emitEvent: (streamId: string, event: StreamEvent) => void;
116→  updateSessionStatus: (
117→    sessionId: string,
118→    status: OrchestratorStatus,
119→    error?: string,
120→  ) => Promise<void>;
121→  updateLastEventAt: (sessionId: string) => Promise<void>;
122→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
123→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
124→};
125→
126→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
127→  TERMINAL_ORCHESTRATOR_STATUSES,
128→);
129→
130→/**
131→ * Iterates the SDK message stream, forwarding messages through the event
132→ * bridge. Transitions session to "active" on first message, starts stall
133→ * detection, and stops on terminal status or error.
134→ *
135→ * Returns a Promise that resolves when iteration ends (for testing).
136→ * In production, this is launched fire-and-forget.
137→ */
138→export function startEventIteration(
139→  deps: EventIterationDeps,
140→  messageStream: AsyncIterable<unknown>,
141→  streamId: string,
142→  sessionId: string,
143→): Promise<void> {
144→  const stallDetector = deps.startStallDetector(sessionId, streamId);
145→
146→  const bridge = startEventBridge(
147→    {
148→      emitEvent: deps.emitEvent,
149→      updateLastEventAt: deps.updateLastEventAt,
150→    },
151→    streamId,
152→    sessionId,
153→    stallDetector,
154→  );
155→
156→  let firstMessageReceived = false;
157→  let messageCount = 0;
158→
159→  async function iterate(): Promise<void> {
160→    logInfo("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
161→    try {
162→      for await (const rawMessage of messageStream) {
163→        messageCount++;
164→        const msg = rawMessage as SdkMessage;
165→        logInfo("orchestrator.iteration", `SDK message received (#${messageCount})`, {
166→          sessionId,
167→          messageType: msg.type,
168→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
169→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
170→        });
171→
172→        // Check if session has reached terminal status
173→        const currentStatus = await deps.getSessionStatus(sessionId);
174→        if (TERMINAL_STATUSES.has(currentStatus)) {
175→          logInfo("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
176→          break;
177→        }
178→
179→        // Transition to active on first message
180→        if (!firstMessageReceived) {
181→          firstMessageReceived = true;
182→          await deps.updateSessionStatus(sessionId, "active");
183→        }
184→
185→        // Forward through event bridge (transform + emit + stall detection)
186→        bridge.handleMessage(msg);
187→      }
188→      logInfo("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
189→      // Transition to idle when stream ends normally and agent produced output
190→      if (firstMessageReceived) {
191→        const finalStatus = await deps.getSessionStatus(sessionId);
192→        if (!TERMINAL_STATUSES.has(finalStatus)) {
193→          await deps.updateSessionStatus(sessionId, "idle");
194→        }
195→      }
196→    } catch (err) {
197→      const errorMessage = err instanceof Error ? err.message : String(err);
198→      logError("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
199→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
200→    } finally {
201→      if (!firstMessageReceived) {
202→        logWarn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
203→      }
204→      bridge.stop();
205→      handleRegistry.delete(sessionId);
206→    }
207→  }
208→
209→  return iterate();
210→}
