212→// ---------------------------------------------------------------------------
213→// Pure helpers
214→// ---------------------------------------------------------------------------
215→
216→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
217→  const result: Record<string, unknown> = {};
218→  for (const [key, value] of Object.entries(obj)) {
219→    if (value !== undefined) {
220→      result[key] = value;
221→    }
222→  }
223→  return result as Partial<T>;
224→}
225→
226→function sessionNotFound(sessionId: string): SessionError {
227→  return {
228→    code: "SESSION_NOT_FOUND",
229→    message: `Session not found: ${sessionId}`,
230→    httpStatus: 404,
231→  };
232→}
233→
234→function worktreeError(message: string): SessionError {
235→  return {
236→    code: "WORKTREE_ERROR",
237→    message,
238→    httpStatus: 500,
239→  };
240→}
241→
242→function fromAssignmentError(error: AssignmentError): SessionError {
243→  return {
244→    code: error.code as SessionErrorCode,
245→    message: error.message,
246→    httpStatus: error.httpStatus,
247→  };
248→}
249→
250→// ---------------------------------------------------------------------------
251→// Session row shape (DB query result)
252→// ---------------------------------------------------------------------------
253→
254→type SessionRow = {
255→  id: RecordId<"agent_session", string>;
256→  orchestrator_status?: string;
257→  worktree_branch?: string;
258→  worktree_path?: string;
259→  started_at?: string;
260→  last_event_at?: string;
261→  task_id?: RecordId<"task", string>;
262→  workspace?: RecordId<"workspace", string>;
263→  error?: string;
264→};
265→
266→type SessionLookup =
267→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
268→  | { ok: false; error: SessionError };
269→
270→async function lookupSession(
271→  surreal: Surreal,
272→  sessionId: string,
273→): Promise<SessionLookup> {
274→  const record = new RecordId("agent_session", sessionId);
275→  const session = await surreal.select<SessionRow>(record);
276→  if (!session) {
277→    return { ok: false, error: sessionNotFound(sessionId) };
278→  }
279→  if (!session.orchestrator_status) {
280→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
281→  }
282→  const status = session.orchestrator_status as OrchestratorStatus;
283→  return { ok: true, session, record, status };
284→}
285→
286→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
287→  if (!session.workspace) {
288→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
289→  }
290→  return session.workspace as RecordId<"workspace", string>;
291→}
292→
293→function generateStreamId(sessionId: string): string {
294→  return `stream-${sessionId}`;
295→}
296→
297→function slugFromTitle(title: string): string {
298→  return title
299→    .toLowerCase()
300→    .replace(/[^a-z0-9]+/g, "-")
301→    .replace(/^-|-$/g, "")
302→    .slice(0, 50);
303→}
304→
305→// ---------------------------------------------------------------------------
306→// createOrchestratorSession
307→// ---------------------------------------------------------------------------
308→
309→type CreateSessionInput = {
310→  surreal: Surreal;
311→  shellExec: ShellExec;
312→  brainBaseUrl: string;
313→  workspaceId: string;
314→  taskId: string;
315→  intentId?: string;
316→  authToken?: string;
317→  spawnAgent?: SpawnAgentFn;
318→  validateAssignment: (
319→    surreal: Surreal,
320→    workspaceId: string,
321→    taskId: string,
322→  ) => Promise<AssignmentResult>;
323→  createAgentSession: (input: {
324→    surreal: Surreal;
325→    agent: string;
326→    workspaceRecord: RecordId<"workspace", string>;
327→    taskId?: string;
328→  }) => Promise<{ session_id: string }>;
329→};
330→
331→export async function createOrchestratorSession(
332→  input: CreateSessionInput,
333→): Promise<OrchestratorSessionResult> {
334→  // 0. Intent authorization gate (optional — backwards compatible)
335→  if (input.intentId) {
336→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
337→    if (!gateResult.ok) {
338→      return { ok: false, error: gateResult.error };
339→    }
340→  }
341→
342→  // 1. Validate assignment eligibility
343→  const assignmentResult = await input.validateAssignment(
344→    input.surreal,
345→    input.workspaceId,
346→    input.taskId,
347→  );
348→
349→  if (!assignmentResult.ok) {
350→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
351→  }
352→
353→  const { validation } = assignmentResult;
354→  const taskSlug = `${slugFromTitle(validation.title)}-${Date.now()}`;
355→  const repoRoot = validation.repoPath;
356→
357→  // 2. Create worktree
358→  const worktreeResult = await createWorktree(
359→    input.shellExec,
360→    repoRoot,
361→    taskSlug,
362→  );
363→
364→  if (!worktreeResult.ok) {
365→    return {
366→      ok: false,
367→      error: worktreeError(worktreeResult.error.message),
368→    };
369→  }
370→
371→  const { branchName, worktreePath } = worktreeResult.value;
372→
373→  // 3. Create agent_session record
374→  const { session_id: agentSessionId } = await input.createAgentSession({
375→    surreal: input.surreal,
376→    agent: "claude-agent-sdk",
377→    workspaceRecord: validation.workspaceRecord,
378→    taskId: input.taskId,
379→  });
380→
381→  const streamId = generateStreamId(agentSessionId);
382→
383→  // 4. Build config and spawn agent
384→  const agentSpawnConfig: AgentSpawnConfig = {
385→    prompt: `/brain-start-task ${input.taskId}`,
386→    workDir: worktreePath,
387→    workspaceId: input.workspaceId,
388→    brainBaseUrl: input.brainBaseUrl,
389→  };
390→
391→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
392→  let handle: AgentHandle;
393→  try {
394→    handle = spawnFn(agentSpawnConfig);
395→  } catch (err) {
396→    // Rollback: remove worktree and delete agent_session on spawn failure
397→    await removeWorktree(input.shellExec, repoRoot, branchName);
398→    const sessionRecord = new RecordId("agent_session", agentSessionId);
399→    await input.surreal.delete(sessionRecord);
400→    return {
401→      ok: false,
402→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
403→    };
404→  }
405→
406→  // 5. Register handle for later abort
407→  handleRegistry.set(agentSessionId, handle);
408→
409→  // 6. Update agent_session with orchestrator fields
410→  const sessionRecord = new RecordId("agent_session", agentSessionId);
411→  await input.surreal.update(sessionRecord).merge({
412→    orchestrator_status: "spawning" as OrchestratorStatus,
413→    worktree_branch: branchName,
414→    worktree_path: worktreePath,
415→    stream_id: streamId,
416→  });
417→
418→  // 7. Transition intent to executing and create gates relation
419→  if (input.intentId) {
420→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
421→  }
422→
423→  return {
424→    ok: true,
425→    value: {
426→      agentSessionId,
427→      streamId,
428→      worktreeBranch: branchName,
429→    },
430→  };
431→}
432→
433→// ---------------------------------------------------------------------------
434→// Intent authorization helpers
435→// ---------------------------------------------------------------------------
436→
437→async function checkIntentAuthorization(
438→  surreal: Surreal,
439→  intentId: string,
440→  workspaceId: string,
441→): Promise<SessionResult<void>> {
442→  const intent = await getIntentById(surreal, intentId);
443→  if (!intent) {
444→    return {
445→      ok: false,
446→      error: {
447→        code: "INTENT_NOT_AUTHORIZED",
448→        message: `Intent ${intentId} not found`,
449→        httpStatus: 404,
450→      },
451→    };
452→  }
453→
454→  // Validate workspace scope: intent must belong to the session's workspace
455→  const intentWorkspaceId = intent.workspace.id as string;
456→  if (intentWorkspaceId !== workspaceId) {
457→    return {
458→      ok: false,
459→      error: {
460→        code: "WORKSPACE_MISMATCH",
461→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
462→        httpStatus: 403,
463→      },
464→    };
465→  }
466→
467→  const status = intent.status as IntentStatus;
468→  if (status !== "authorized") {
469→    return {
470→      ok: false,
471→      error: {
472→        code: "INTENT_NOT_AUTHORIZED",
473→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
474→        httpStatus: 403,
475→      },
476→    };
477→  }
478→
479→  return { ok: true, value: undefined as void };
480→}
481→
482→async function transitionIntentToExecuting(
483→  surreal: Surreal,
484→  intentId: string,
485→  sessionRecord: RecordId<"agent_session", string>,
486→): Promise<void> {
487→  await updateIntentStatus(surreal, intentId, "executing");
488→
489→  const intentRecord = new RecordId("intent", intentId);
490→  await surreal.query(
491→    "RELATE $intent->gates->$session SET created_at = time::now();",
492→    { intent: intentRecord, session: sessionRecord },
493→  );
494→
495→  logInfo("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
496→    intentId,
497→    sessionId: sessionRecord.id as string,
498→  });
499→}
500→
501→// Default spawn -- placeholder for production use
502→function defaultSpawnAgent(
503→  _config: AgentSpawnConfig,
504→): AgentHandle {
505→  throw new Error(
506→    "spawnAgent not provided -- must be injected for production use",
507→  );
508→}
509→
510→// ---------------------------------------------------------------------------
511→// getOrchestratorSessionStatus
512→// ---------------------------------------------------------------------------
513→
514→type GetStatusInput = {
515→  surreal: Surreal;
516→  sessionId: string;
517→};
518→
519→export async function getOrchestratorSessionStatus(
520→  input: GetStatusInput,
521→): Promise<SessionStatusResult> {
522→  const lookup = await lookupSession(input.surreal, input.sessionId);
523→  if (!lookup.ok) {
524→    return { ok: false, error: lookup.error };
525→  }
526→  const { session } = lookup;
527→
528→  return {
529→    ok: true,
530→    value: {
531→      orchestratorStatus: lookup.status,
532→      ...pickDefined({
533→        worktreeBranch: session.worktree_branch,
534→        worktreePath: session.worktree_path,
535→        startedAt: session.started_at,
536→        lastEventAt: session.last_event_at,
537→        error: session.error,
538→      }),
539→    },
540→  };
541→}
542→
543→// ---------------------------------------------------------------------------
544→// abortOrchestratorSession
545→// ---------------------------------------------------------------------------
546→
547→type AbortSessionInput = {
548→  surreal: Surreal;
549→  shellExec: ShellExec;
550→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
551→  sessionId: string;
552→  endAgentSession: (input: {
553→    surreal: Surreal;
554→    workspaceRecord: RecordId<"workspace", string>;
555→    sessionId: string;
556→    summary: string;
557→  }) => Promise<{ session_id: string; ended: boolean }>;
558→};
559→
560→export async function abortOrchestratorSession(
561→  input: AbortSessionInput,
562→): Promise<AbortSessionResult> {
563→  const lookup = await lookupSession(input.surreal, input.sessionId);
564→  if (!lookup.ok) {
565→    return { ok: false, error: lookup.error };
566→  }
567→  const { session, record: sessionRecord } = lookup;
568→
569→  // 1. Abort the agent process if handle exists
570→  const handle = handleRegistry.get(input.sessionId);
571→  if (handle) {
572→    handle.abort();
573→    handleRegistry.delete(input.sessionId);
574→  }
575→
576→  // 2. Update orchestrator_status to aborted
577→  await input.surreal.update(sessionRecord).merge({
578→    orchestrator_status: "aborted" as OrchestratorStatus,
579→  });
580→
581→  const workspaceRecord = requireWorkspace(session, input.sessionId);
582→
583→  // 3. Remove worktree if branch name exists
584→  if (session.worktree_branch) {
585→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
586→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
587→  }
588→
589→  // 4. Return task to ready
590→  if (session.task_id) {
591→    await input.surreal.update(session.task_id).merge({
592→      status: "ready",
593→      updated_at: new Date(),
594→    });
595→  }
596→
597→  // 5. End the agent session
598→  await input.endAgentSession({
599→    surreal: input.surreal,
600→    workspaceRecord,
601→    sessionId: input.sessionId,
602→    summary: "Session aborted",
603→  });
604→
605→  return {
606→    ok: true,
607→    value: {
608→      aborted: true,
609→      sessionId: input.sessionId,
610→    },
611→  };
612→}
613→
614→// ---------------------------------------------------------------------------
615→// acceptOrchestratorSession
616→// ---------------------------------------------------------------------------
617→
618→type AcceptSessionInput = {
619→  surreal: Surreal;
620→  sessionId: string;
621→  summary: string;
622→  endAgentSession: (input: {
623→    surreal: Surreal;
624→    workspaceRecord: RecordId<"workspace", string>;
625→    sessionId: string;
626→    summary: string;
627→  }) => Promise<{ session_id: string; ended: boolean }>;
628→};
629→
630→export async function acceptOrchestratorSession(
631→  input: AcceptSessionInput,
632→): Promise<AcceptSessionResult> {
633→  const lookup = await lookupSession(input.surreal, input.sessionId);
634→  if (!lookup.ok) {
635→    return { ok: false, error: lookup.error };
636→  }
637→  const { session, record: sessionRecord, status } = lookup;
638→
639→  if (!ACCEPTABLE_STATUSES.has(status)) {
640→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
641→  }
642→
643→  const workspaceRecord = requireWorkspace(session, input.sessionId);
644→
645→  // 1. Update orchestrator_status to completed
646→  await input.surreal.update(sessionRecord).merge({
647→    orchestrator_status: "completed" as OrchestratorStatus,
648→  });
649→
650→  // 2. Clean up handle registry
651→  handleRegistry.delete(input.sessionId);
652→
653→  // 4. End the agent session
654→  await input.endAgentSession({
655→    surreal: input.surreal,
656→    workspaceRecord,
657→    sessionId: input.sessionId,
658→    summary: input.summary,
659→  });
660→
661→  return {
662→    ok: true,
663→    value: {
664→      accepted: true,
665→      sessionId: input.sessionId,
666→    },
667→  };
668→}
669→
670→// ---------------------------------------------------------------------------
671→// State guard helpers
672→// ---------------------------------------------------------------------------
673→
674→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
675→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
676→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
677→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
678→
679→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
680→  return {
681→    code: "SESSION_ERROR",
682→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
683→    httpStatus: 409,
684→  };
685→}
686→
687→function sessionAborted(sessionId: string): SessionError {
688→  return {
689→    code: "SESSION_ERROR",
690→    message: `Session ${sessionId} has been aborted`,
691→    httpStatus: 409,
692→  };
693→}
694→
695→// ---------------------------------------------------------------------------
696→// getOrchestratorReview
697→// ---------------------------------------------------------------------------
698→
699→type GetReviewInput = {
700→  surreal: Surreal;
701→  sessionId: string;
702→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
703→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
704→  getTaskTitle: (taskId: string) => Promise<string>;
705→};
706→
707→export async function getOrchestratorReview(
708→  input: GetReviewInput,
